css:
.print-heading {
  text-align: center;
  margin-bottom: 30px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

table th.table-sr { display: none; }

table td.table-sr { display: none; }

.term-table {
  width: 100%;
  border-collapse: separate;  /* Needed for radius */
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.term-table th,
.term-table td {
  padding: 8px;
}

/* Top row background */
.term-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
}

/* All table cells: bottom + right borders for grid lines */
.term-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

/* Remove right border on last column */
.term-table td:last-child,
.term-table th:last-child {
  border-right: none;
}

/* Remove bottom border on last row */
.term-table tbody tr:last-child td {
  border-bottom: none;
}

/* Zebra stripes */
.term-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.section-heading {
  border-bottom: 1px solid #b40000;
  padding-bottom: 5px;
  margin-top: 20px;
  margin-bottom: 10px;
  font-size: 12pt;
  font-weight: 700;
  page-break-after: avoid;
}

.sig-grid {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
  border: 1px solid #000;
  margin-top: 12px;
  margin-bottom: 16px;
}

.sig-grid th,
.sig-grid td {
  border: 1px solid #000;
  padding: 6px 8px;
  vertical-align: top;
}

.sig-grid th {
  font-weight: 700;
  text-align: center;
  background: #f5f5f5;
}

.sig-rowlabel {
  font-weight: 700;
  background: #fafafa;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 30px;
}

.signatures td {
  border: none;           /* No borders here */
  padding: 20px 0;        /* Spacing for signatures */
  vertical-align: top;
}

.signatures p {
  margin: 0;
  font-size: 12pt;
}

@page {
  margin: 20mm 15mm 25mm 15mm; /* top right bottom left */
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
